n, m = map(int, input().split())
a = [input() for i in range(n)]

def check(a, b):
    for i in range(n):
        for j in range(m):
            if a[i][j] != b[i][j]:
                return False
    return True

def mirror(a):
    b = ["" for i in range(n)]
    for i in range(n):
        for j in range(m):
            b[i] += str(1 - int(a[i][j]))
    return b

def solve(a):
    b = a[::]
    for i in range(n):
        for j in range(n):
            b = mirror(b)
            if check(a, b):
                return b
    return None

b = solve(a)
if b is None:
    print(n)
else:
    print(n // 2 + 1)
